export const Schema = z.object({
    系统: z.object({
        当前时间: z.string().prefault('第一天 上午'),
        当前位置: z.string().prefault('幸福村'),
        当前场景: z.string().prefault('广场'),
    }).prefault({}),
    主角: z.object({
        精液罐余量: z.coerce.number().transform(v => _.clamp(v, 0, Infinity)).prefault(0),
        身体状态: z.object({
            体力: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(100),
            性奋度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
            压力: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
        }).prefault({}),
        _睾丸储量: z.coerce.number().transform(v => _.clamp(v, 0, 20)).prefault(20),
    }).prefault({}),
});
